-- Travel Select players — Summer 2026
-- 97 players across 7 teams

on conflict (id) do update set
  name = excluded.name, grade = excluded.grade, school = excluded.school,
  guardian = excluded.guardian, phone = excluded.phone,
  program = excluded.program, division = excluded.division, team = excluded.team,
  status = excluded.status, waiver = excluded.waiver;
